package com.example.kafka;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;
import org.springframework.util.concurrent.ListenableFuture;

import java.util.concurrent.CompletableFuture;

@Service
public class KafkaProducerService {

    @Autowired
    private KafkaTemplate<String, Object> kafkaTemplate;

    public void sendMessage(String topic, String key, Object message) {
        ListenableFuture<SendResult<String, Object>> future = kafkaTemplate.send(topic, key, message);
        future.addCallback(
                result -> System.out.println("Sent message=[" + message + "] with offset=[" + result.getRecordMetadata().offset() + "]"),
                exception -> System.err.println("Unable to send message=[" + message + "] due to : " + exception.getMessage())
        );
    }

    public CompletableFuture<SendResult<String, Object>> sendMessageAsync(String topic, String key, Object message) {
        return CompletableFuture.supplyAsync(() -> kafkaTemplate.send(topic, key, message).get());
    }
}

